import numpy as np

# Common backbone idea: Both algorithms focus on prioritizing nodes based on travel times, time windows, and penalties for waiting or delays.

# {This algorithm incorporates adaptive re-evaluation of priorities based on shifting urgency and spatial importance relative to cluster density of customers.}

def select_next_node(cur_truck_pos, depot_pos, all_truck_pos, unvisited_customers, current_time, truck_speed, time_windows):
    if not unvisited_customers:
        return None

    best_node = None
    min_dynamic_cost = float('inf')

    for idx, customer_pos in enumerate(unvisited_customers):
        travel_time = np.linalg.norm(cur_truck_pos - customer_pos) / truck_speed
        arrival_time = current_time + travel_time
        start, end = time_windows[idx]

        if arrival_time < start:
            wait_time = start - arrival_time
            arrival_time = start
        else:
            wait_time = 0

        if arrival_time <= end:
            # Calculate cluster density
            cluster_density = sum(np.linalg.norm(customer_pos - other_pos) < truck_speed for other_pos in unvisited_customers)

            urgency = 1 / (end - arrival_time + 1)
            dynamic_cost = (travel_time + 1) * (1 + wait_time) / (urgency + 1) * (1 + cluster_density)

            if dynamic_cost < min_dynamic_cost:
                min_dynamic_cost = dynamic_cost
                best_node = idx

    return best_node
